#include<bits/stdc++.h>
using namespace std;
int r[301][301],max1[301],min1[301],a[301];
int main()
{
	int n;
	scanf("%d",&n);
	for(int i=1;i<=n;i++)
	{
		for(int j=i;j<=n;j++)
		{
			scanf("%d",&r[i][j]);
		}
	}
	for(int i=1;i<=n;i++)
	{
		max1[i]=-1e9;
		min1[i]=1e9;
	}
	a[1]=0;
	max1[1]=0;
	min1[1]=0;
	for(int i=2;i<=n;i++)
	{
		int temp=a[i-1]+r[i-1][i];
		bool flag=true;
		for(int j=1;j<i;j++)
		{
			if(max(max1[j],temp)-min(min1[j],temp)!=r[j][i])
			{
				flag=false;
				break;
			}
		}
		if(!flag)
		{
			temp=a[i-1]-r[i-1][i];
		}
		for(int j=1;j<=i;j++)
		{
			max1[j]=max(max1[j],temp);
			min1[j]=min(min1[j],temp);
		}
		a[i]=temp;
	}
	for(int i=1;i<=n;i++)
	{
		printf("%d ",a[i]);
	}
	return 0;
}
